#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);
    int arr[10]; // Maximum N is 10
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }
    for (int i = n - 1; i >= 0; i--) {
        printf("%d", arr[i]);
        if (i > 0) {
            printf(" ");
        }
    }
    printf("\n");
    return 0;
}

#include <stdio.h>
#include <string.h> // For strlen

int main() {
    char word[51]; // 50 characters + null terminator
    scanf("%s", word);
    int length = strlen(word);
    int isPalindrome = 1; // Assume it's a palindrome
    for (int i = 0; i < length / 2; i++) {
        if (word[i] != word[length - 1 - i]) {
            isPalindrome = 0; // Found a mismatch
            break;
        }
    }
    if (isPalindrome) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }
    return 0;
}

#include <stdio.h>
#include <string.h> // For fgets, strcspn
#include <ctype.h>  // For tolower, isalpha

int main() {
    char line[101]; // 100 chars + null terminator
    int counts[26] = {0}; // Array for 'a' through 'z'

    // Read a line including spaces
    fgets(line, sizeof(line), stdin);

    // Remove newline character if present
    line[strcspn(line, "\n")] = 0;

    for (int i = 0; line[i] != '\0'; i++) {
        char c = tolower(line[i]); // Convert to lowercase
        if (isalpha(c)) { // Check if it's an alphabet character
            counts[c - 'a']++; // Increment count for the corresponding letter
        }
    }

    for (int i = 0; i < 26; i++) {
        if (counts[i] > 0) {
            printf("%c:%d\n", (char)('a' + i), counts[i]);
        }
    }

    return 0;
}

#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);
    int arr[100]; // Maximum N is 100
    long long sum = 0; // Use long long for sum to prevent overflow
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
        sum += arr[i];
    }
    printf("%lld\n", sum);
    // Calculate average as float, ensure float division
    printf("%.2f\n", (float)sum / n);
    return 0;
}

#include <stdio.h>
#include <string.h> // For fgets, strcspn
#include <ctype.h>  // For isupper, islower, tolower, toupper

int main() {
    char line[81]; // 80 chars + null terminator
    fgets(line, sizeof(line), stdin);

    // Remove newline character if present
    line[strcspn(line, "\n")] = 0;

    for (int i = 0; line[i] != '\0'; i++) {
        if (isupper(line[i])) {
            line[i] = tolower(line[i]);
        } else if (islower(line[i])) {
            line[i] = toupper(line[i]);
        }
        // Other characters are left unchanged
    }
    printf("%s\n", line);
    return 0;
}

#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);
    int original_arr[20]; // Maximum N is 20
    int positive_arr[20]; // To store filtered positive numbers
    int positive_count = 0;

    for (int i = 0; i < n; i++) {
        scanf("%d", &original_arr[i]);
        if (original_arr[i] > 0) {
            positive_arr[positive_count] = original_arr[i];
            positive_count++;
        }
    }

    for (int i = 0; i < positive_count; i++) {
        printf("%d", positive_arr[i]);
        if (i < positive_count - 1) {
            printf(" ");
        }
    }
    printf("\n");
    return 0;
}

#include <stdio.h>
#include <string.h> // For fgets, strcspn
#include <ctype.h>  // For isspace

int main() {
    char line[101]; // 100 chars + null terminator
    fgets(line, sizeof(line), stdin);

    // Remove newline character if present
    line[strcspn(line, "\n")] = 0;

    int word_count = 0;
    int in_word = 0; // Flag: 0 if not in a word, 1 if in a word

    for (int i = 0; line[i] != '\0'; i++) {
        if (isspace(line[i])) {
            in_word = 0; // Exited a word
        } else if (in_word == 0) { // If not in a word and current char is not space, it's a new word
            word_count++;
            in_word = 1;
        }
    }
    printf("%d\n", word_count);
    return 0;
}

#include <stdio.h>

int main() {
    int n;
    scanf("%d", &n);
    int arr[15]; // Maximum N is 15
    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    if (n > 0) { // Only rotate if array is not empty
        int first_element = arr[0]; // Store the first element
        for (int i = 0; i < n - 1; i++) {
            arr[i] = arr[i+1]; // Shift elements to the left
        }
        arr[n-1] = first_element; // Place the stored first element at the end
    }

    for (int i = 0; i < n; i++) {
        printf("%d", arr[i]);
        if (i < n - 1) {
            printf(" ");
        }
    }
    printf("\n");
    return 0;
}

#include <stdio.h>
#include <string.h> // For strlen

int main() {
    char text[31]; // Max 30 chars + null
    char pattern[31]; // Max 30 chars + null

    scanf("%s", text);
    scanf("%s", pattern);

    int text_len = strlen(text);
    int pattern_len = strlen(pattern);
    int found = 0;

    // A pattern can only be a substring if its length is less than or equal to the text's length.
    // Also, problems states "lowercase English letters only", implying non-empty strings.
    if (pattern_len <= text_len) {
        // Iterate through text, checking potential starting points for pattern
        for (int i = 0; i <= text_len - pattern_len; i++) {
            int match = 1; // Assume match for current starting position in text
            // Check if substring of text starting at 'i' matches pattern
            for (int j = 0; j < pattern_len; j++) {
                if (text[i + j] != pattern[j]) {
                    match = 0; // Mismatch found, break inner loop
                    break;
                }
            }
            if (match) {
                found = 1; // Full pattern matched
                break; // Break outer loop as pattern is found
            }
        }
    }

    if (found) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }

    return 0;
}

#include <stdio.h>

int main() {
    int R, C;
    scanf("%d %d", &R, &C);

    int matrix[3][3]; // Maximum R=3, C=3

    // Read matrix elements
    for (int i = 0; i < R; i++) {
        for (int j = 0; j < C; j++) {
            scanf("%d", &matrix[i][j]);
        }
    }

    // Calculate and print row sums
    for (int i = 0; i < R; i++) {
        int row_sum = 0;
        for (int j = 0; j < C; j++) {
            row_sum += matrix[i][j];
        }
        printf("%d\n", row_sum);
    }

    return 0;
}
